import React from 'react';
import PropTypes from 'prop-types';
import { library } from '@fortawesome/fontawesome-svg-core';
import { fab } from '@fortawesome/free-brands-svg-icons';
import { faBars, faArrowRight, faArrowLeft, faPlayCircle, faChevronUp, faChevronDown, faTimesCircle, faTimes, faFileDownload, faTh, faBorderAll, faSearch } from '@fortawesome/free-solid-svg-icons'

import Header from '../header';
import Footer from '../footer';

library.add(fab, faBars, faArrowRight, faArrowLeft, faPlayCircle, faChevronUp, faChevronDown, faTimesCircle, faTimes, faFileDownload, faTh, faBorderAll, faSearch);

const Layout = ({ children, is404 }) => {
  return (
    <>
      {!is404 ? <Header /> : null}
      <div>
        <main>{children}</main>
        {!is404 ? <Footer /> : null}
      </div>
    </>
  )
}

Layout.propTypes = {
  children: PropTypes.node.isRequired,
}

export default Layout
