import React from 'react';
import { graphql, useStaticQuery, Link } from 'gatsby';
import get from 'lodash/get';
import map from 'lodash/map';

let Subtypes = () => {
  let data = useStaticQuery(graphql`
  {
    allStrapiProductSubtypes {
      edges {
        node {
          image {
            childImageSharp {
              fluid {
                src
              }
            }
          }
          name
          slug
        }
      }
    }
  }
  `);

  return (
    <section className="find-products-as">
      <h1>También encuéntralos como</h1>
        <div className="inline-list">
          {
            map(data.allStrapiProductSubtypes.edges, (({node}) => (
              <Link className="sub-type" to={`/productos/${node.slug}`}>
                <img src={get(node, 'image.childImageSharp.fluid.src')} />
                <div>
                  {node.name}
                </div>
              </Link>
            )))
          }
      </div>
    </section>
  )
}

export default Subtypes;
